{
  "version": "arkpilot-a2ui/v2",
  "kind": "semantic-ui-protocol",
  "appName": "今天吃什么",
  "targetDevice": {
    "widthVp": 1272,
    "heightVp": 2756,
    "contentMaxWidthVp": 420
  },
  "surfaces": [
    {
      "id": "home-page",
      "surfaceId": "home",
      "pageId": "home-page",
      "name": "Home",
      "route": "pages/Home",
      "tabId": "tab-home",
      "semanticTargets": [
        {
          "id": "home-header-title",
          "role": "assertion",
          "binding": "pageTitle"
        },
        {
          "id": "home-today-status-card",
          "role": "assertion",
          "binding": "todayMealSummary"
        },
        {
          "id": "home-today-decide-button",
          "role": "action",
          "event": "navigate-to-decide-hub"
        },
        {
          "id": "home-quick-wheel-button",
          "role": "action",
          "event": "navigate-to-wheel"
        },
        {
          "id": "home-quick-fridge-button",
          "role": "action",
          "event": "navigate-to-fridge"
        },
        {
          "id": "home-quick-filter-button",
          "role": "action",
          "event": "navigate-to-filter"
        },
        {
          "id": "home-recent-history-list",
          "role": "list",
          "binding": "recentMealRecords",
          "itemIdPattern": "home-recent-item-{id}",
          "emptyStateId": "home-recent-empty"
        },
        {
          "id": "home-view-history-button",
          "role": "action",
          "event": "navigate-to-history"
        }
      ]
    },
    {
      "id": "decide-hub-page",
      "surfaceId": "decide-hub",
      "pageId": "decide-hub-page",
      "name": "Decide Hub",
      "route": "pages/DecideHub",
      "tabId": "tab-decide",
      "semanticTargets": [
        {
          "id": "decide-segment-wheel",
          "role": "action",
          "event": "switch-to-wheel"
        },
        {
          "id": "decide-segment-fridge",
          "role": "action",
          "event": "switch-to-fridge"
        },
        {
          "id": "decide-segment-filter",
          "role": "action",
          "event": "switch-to-filter"
        },
        {
          "id": "decide-active-surface",
          "role": "assertion",
          "binding": "activeDecideSurface"
        }
      ]
    },
    {
      "id": "wheel-page",
      "surfaceId": "wheel",
      "pageId": "wheel-page",
      "name": "Wheel",
      "route": "pages/Wheel",
      "tabId": "tab-decide",
      "semanticTargets": [
        {
          "id": "wheel-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "wheel-title",
          "role": "assertion",
          "binding": "pageTitle"
        },
        {
          "id": "wheel-canvas",
          "role": "assertion",
          "binding": "wheelState"
        },
        {
          "id": "wheel-spin-button",
          "role": "action",
          "event": "spin-wheel"
        },
        {
          "id": "wheel-result-card",
          "role": "assertion",
          "binding": "wheelResult"
        },
        {
          "id": "wheel-result-name",
          "role": "assertion",
          "binding": "wheelResult.dishName"
        },
        {
          "id": "wheel-result-accept-button",
          "role": "action",
          "event": "accept-wheel-result"
        },
        {
          "id": "wheel-result-spin-again-button",
          "role": "action",
          "event": "spin-wheel"
        }
      ]
    },
    {
      "id": "fridge-page",
      "surfaceId": "fridge",
      "pageId": "fridge-page",
      "name": "Fridge",
      "route": "pages/Fridge",
      "tabId": "tab-decide",
      "semanticTargets": [
        {
          "id": "fridge-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "fridge-ingredient-input",
          "role": "input",
          "event": "add-ingredient",
          "binding": "ingredientInputValue"
        },
        {
          "id": "fridge-add-button",
          "role": "action",
          "event": "add-ingredient"
        },
        {
          "id": "fridge-ingredient-list",
          "role": "list",
          "binding": "fridgeIngredients",
          "itemIdPattern": "fridge-ingredient-{id}",
          "emptyStateId": "fridge-empty"
        },
        {
          "id": "fridge-recommendation-list",
          "role": "list",
          "binding": "fridgeRecommendations",
          "itemIdPattern": "fridge-dish-{id}",
          "emptyStateId": "fridge-recommendations-empty"
        },
        {
          "id": "fridge-clear-button",
          "role": "action",
          "event": "clear-ingredients"
        }
      ]
    },
    {
      "id": "filter-page",
      "surfaceId": "filter",
      "pageId": "filter-page",
      "name": "Filter",
      "route": "pages/Filter",
      "tabId": "tab-decide",
      "semanticTargets": [
        {
          "id": "filter-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "filter-mood-selector",
          "role": "input",
          "event": "select-mood",
          "binding": "selectedMood"
        },
        {
          "id": "filter-time-selector",
          "role": "input",
          "event": "select-meal-time",
          "binding": "selectedMealTime"
        },
        {
          "id": "filter-recommendation-list",
          "role": "list",
          "binding": "filterRecommendations",
          "itemIdPattern": "filter-dish-{id}",
          "emptyStateId": "filter-recommendations-empty"
        },
        {
          "id": "filter-reset-button",
          "role": "action",
          "event": "reset-filters"
        }
      ]
    },
    {
      "id": "history-page",
      "surfaceId": "history",
      "pageId": "history-page",
      "name": "History",
      "route": "pages/History",
      "tabId": "tab-history",
      "semanticTargets": [
        {
          "id": "history-header-title",
          "role": "assertion",
          "binding": "pageTitle"
        },
        {
          "id": "history-today-count",
          "role": "assertion",
          "binding": "todayRecordCount"
        },
        {
          "id": "history-record-list",
          "role": "list",
          "binding": "mealRecords",
          "itemIdPattern": "history-record-{id}",
          "emptyStateId": "history-empty"
        },
        {
          "id": "history-share-button",
          "role": "action",
          "event": "open-share-sheet",
          "context": { "source": "history" }
        },
        {
          "id": "history-delete-button",
          "role": "action",
          "event": "delete-record",
          "context": { "destructive": true }
        }
      ]
    },
    {
      "id": "share-sheet",
      "surfaceId": "share",
      "pageId": "share-page",
      "name": "Share",
      "route": "pages/Share",
      "tabId": null,
      "semanticTargets": [
        {
          "id": "share-close-button",
          "role": "action",
          "event": "close-share-sheet"
        },
        {
          "id": "share-preview-card",
          "role": "assertion",
          "binding": "shareCardPreview"
        },
        {
          "id": "share-template-selector",
          "role": "input",
          "event": "select-template",
          "binding": "selectedTemplate"
        },
        {
          "id": "share-save-button",
          "role": "action",
          "event": "save-share-card"
        },
        {
          "id": "share-copy-button",
          "role": "action",
          "event": "copy-share-card"
        },
        {
          "id": "share-system-button",
          "role": "action",
          "event": "open-system-share"
        }
      ]
    }
  ],
  "events": [
    { "name": "navigate-to-decide-hub", "description": "Open the Decide hub defaulting to Wheel." },
    { "name": "navigate-to-wheel", "description": "Open the Wheel surface." },
    { "name": "navigate-to-fridge", "description": "Open the Fridge surface." },
    { "name": "navigate-to-filter", "description": "Open the Filter surface." },
    { "name": "navigate-to-history", "description": "Open the History tab." },
    { "name": "navigate-back", "description": "Return to the previous surface." },
    { "name": "switch-to-wheel", "description": "Switch Decide hub to Wheel segment." },
    { "name": "switch-to-fridge", "description": "Switch Decide hub to Fridge segment." },
    { "name": "switch-to-filter", "description": "Switch Decide hub to Filter segment." },
    { "name": "spin-wheel", "description": "Start or restart the wheel animation and resolve a random dish." },
    { "name": "accept-wheel-result", "description": "Save the current wheel result as a meal record and open history." },
    { "name": "add-ingredient", "description": "Add the current input value to the fridge ingredient list." },
    { "name": "clear-ingredients", "description": "Remove all ingredients from the fridge list." },
    { "name": "select-mood", "description": "Choose a mood tag." },
    { "name": "select-meal-time", "description": "Choose a meal time tag." },
    { "name": "reset-filters", "description": "Clear mood and meal time selections." },
    { "name": "open-share-sheet", "description": "Open the share sheet for a given meal record." },
    { "name": "close-share-sheet", "description": "Close the share sheet." },
    { "name": "save-share-card", "description": "Save the generated share card image to the device." },
    { "name": "copy-share-card", "description": "Copy the share card image to the clipboard." },
    { "name": "open-system-share", "description": "Trigger the system share sheet for the share card." },
    { "name": "delete-record", "description": "Delete a meal record from history." }
  ],
  "bindings": [
    { "path": "todayMealSummary", "type": "object|null" },
    { "path": "recentMealRecords", "type": "array" },
    { "path": "activeDecideSurface", "type": "enum", "values": ["wheel", "fridge", "filter"] },
    { "path": "wheelState", "type": "enum", "values": ["idle", "spinning", "result"] },
    { "path": "wheelResult.dishName", "type": "string" },
    { "path": "ingredientInputValue", "type": "string" },
    { "path": "fridgeIngredients", "type": "array" },
    { "path": "fridgeRecommendations", "type": "array" },
    { "path": "selectedMood", "type": "string|null" },
    { "path": "selectedMealTime", "type": "string|null" },
    { "path": "filterRecommendations", "type": "array" },
    { "path": "todayRecordCount", "type": "number" },
    { "path": "mealRecords", "type": "array" },
    { "path": "shareCardPreview", "type": "object" },
    { "path": "selectedTemplate", "type": "string" }
  ],
  "testTargets": [
    { "id": "home-today-decide-button", "action": "tap", "expected": "opens Decide hub" },
    { "id": "wheel-spin-button", "action": "tap", "expected": "wheel spins and result appears" },
    { "id": "wheel-result-accept-button", "action": "tap", "expected": "record saved and history opens" },
    { "id": "fridge-ingredient-input", "action": "input+submit", "expected": "ingredient added to list" },
    { "id": "fridge-recommendation-list", "action": "assert", "expected": "shows matching dishes" },
    { "id": "filter-mood-selector", "action": "select", "expected": "recommendations update" },
    { "id": "history-record-list", "action": "assert", "expected": "records visible or empty state shown" },
    { "id": "history-share-button", "action": "tap", "expected": "share sheet opens" },
    { "id": "share-save-button", "action": "tap", "expected": "image saved prompt shown" }
  ]
}

